import React, { useState } from "react";

function Auth() {
  const [isLogin, setIsLogin] = useState(true);

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-b from-[#050B2C] to-[#020617] text-white">

      <div className="w-[380px] bg-white/5 border border-white/10 p-8 rounded-2xl backdrop-blur-md">

        <h2 className="text-3xl font-bold text-center text-blue-300 mb-6">
          {isLogin ? "Login to HIRETRAX" : "Create Account"}
        </h2>

        <input
          type="email"
          placeholder="Email"
          className="w-full mb-4 p-3 rounded-lg bg-black/30 border border-white/10 outline-none"
        />

        <input
          type="password"
          placeholder="Password"
          className="w-full mb-6 p-3 rounded-lg bg-black/30 border border-white/10 outline-none"
        />

        <button className="w-full bg-blue-500 py-3 rounded-lg hover:bg-blue-600 transition">
          {isLogin ? "Login" : "Sign Up"}
        </button>

        <p className="text-sm text-center mt-5 text-gray-400">
          {isLogin ? "Don't have an account?" : "Already have an account?"}
          <span
            className="text-blue-400 cursor-pointer ml-2"
            onClick={() => setIsLogin(!isLogin)}
          >
            {isLogin ? "Sign Up" : "Login"}
          </span>
        </p>

      </div>
    </div>
  );
}

export default Auth;
